+import React from "react";
+
+type Props = {
+  src?: string;
+  srcdoc?: string;
+  // sandbox flags string as provided by consumers
+  sandbox?: string;
+  // If true, explicitly allow same-origin. Keep false by default (principle of least privilege).
+  allowSameOrigin?: boolean;
+  title?: string;
+  className?: string;
+};
+
+// Minimal, conservative HTML sanitizer that:
+// - Parses the provided HTML string
+// - Reconstructs an output consisting only of allowed elements and allowed attributes
+// - Drops script/style elements, event handler attributes, and javascript: URIs
+// This avoids bringing additional dependencies and is sufficient for iframe srcdoc sanitization.
+const sanitizeHtml = (input: string): string => {
+  if (!input) return "";
+
+  const parser = new DOMParser();
+  const doc = parser.parseFromString(input, "text/html");
+
+  const ALLOWED_TAGS = new Set([
+    "a",
+    "abbr",
+    "b",
+    "br",
+    "code",
+    "div",
+    "em",
+    "i",
+    "img",
+    "li",
+    "ol",
+    "p",
+    "pre",
+    "span",
+    "strong",
+    "ul",
+    "h1",
+    "h2",
+    "h3",
+    "h4",
+    "h5",
+    "h6",
+    "table",
+    "thead",
+    "tbody",
+    "tr",
+    "td",
+    "th",
+  ]);
+
+  // Attributes that are allowed (if present) for elements.
+  const ALLOWED_ATTRS = new Set(["href", "src", "alt", "title", "width", "height", "colspan", "rowspan"]);
+
+  // Helper: strip potentially dangerous URI schemes
+  const isSafeUrl = (val: string) => {
+    if (!val) return false;
+    const trimmed = val.trim().toLowerCase();
+    // Allow only http(s), mailto and relative URLs, data:image/*
+    if (trimmed.startsWith("http://") || trimmed.startsWith("https://") || trimmed.startsWith("/") || trimmed.startsWith("./") || trimmed.startsWith("../") || trimmed.startsWith("mailto:")) {
+      return true;
+    }
+    if (trimmed.startsWith("data:")) {
+      // allow images as data URIs only
+      return /^data:image\/(png|jpeg|jpg|gif|webp);/.test(trimmed);
+    }
+    return false;
+  };
+
+  const walk = (node: Node, outParent: Element | DocumentFragment) => {
+    if (node.nodeType === Node.TEXT_NODE) {
+      outParent.appendChild(doc.createTextNode(node.textContent || ""));
+      return;
+    }
+
+    if (node.nodeType !== Node.ELEMENT_NODE) return;
+
+    const el = node as Element;
+    const tag = el.tagName.toLowerCase();
+
+    if (!ALLOWED_TAGS.has(tag)) {
+      // recurse children but don't keep this tag itself
+      for (let i = 0; i < el.childNodes.length; i++) {
+        walk(el.childNodes[i], outParent);
+      }
+      return;
+    }
+
+    const newEl = doc.createElement(tag);
+
+    // copy allowed attributes only, sanitize URLs and drop event handlers
+    for (let i = 0; i < el.attributes.length; i++) {
+      const attr = el.attributes[i];
+      const name = attr.name.toLowerCase();
+      const value = attr.value;
+      if (name.startsWith("on")) continue; // drop event handlers
+      if (!ALLOWED_ATTRS.has(name)) continue;
+      if ((name === "href" || name === "src")) {
+        if (!isSafeUrl(value)) continue;
+      }
+      newEl.setAttribute(name, value);
+    }
+
+    outParent.appendChild(newEl);
+
+    for (let i = 0; i < el.childNodes.length; i++) {
+      walk(el.childNodes[i], newEl);
+    }
+  };
+
+  const frag = doc.createDocumentFragment();
+  // Only process body to avoid carrying over <head> contents like scripts/styles
+  const body = doc.body;
+  for (let i = 0; i < body.childNodes.length; i++) {
+    walk(body.childNodes[i], frag);
+  }
+
+  // Serialize fragment
+  const container = doc.createElement("div");
+  container.appendChild(frag);
+  return container.innerHTML;
+};
+
+const buildSandboxAttr = (provided?: string, allowSameOrigin = false): string => {
+  // Start with tokens from provided string but filter them
+  const tokens = new Set<string>();
+  if (provided) {
+    provided.split(/\s+/).forEach((t) => {
+      const tk = t.trim();
+      if (!tk) return;
+      // disallow allow-same-origin unless explicitly requested via allowSameOrigin flag
+      if (tk === "allow-same-origin" && !allowSameOrigin) return;
+      // allow only known safe tokens; other tokens are preserved conservatively except "allow-same-origin"
+      tokens.add(tk);
+    });
+  }
+  // Ensure scripts still are allowed if requested by provider (we preserve allow-scripts)
+  // Return tokens joined by space (empty string if none)
+  return Array.from(tokens).join(" ");
+};
+
+const Embed: React.FC<Props> = ({ src, srcdoc, sandbox = "allow-scripts", allowSameOrigin = false, title = "", className }) => {
+  // sanitize srcdoc input before using it in the iframe
+  const safeSrcDoc = srcdoc ? sanitizeHtml(srcdoc) : undefined;
+  const safeSandbox = buildSandboxAttr(sandbox, allowSameOrigin);
+
+  // If src is provided, ensure it's a safe URL; otherwise omit it.
+  const safeSrc = (() => {
+    if (!src) return undefined;
+    try {
+      // use URL parsing to reject javascript: pseudo-URLs
+      const u = new URL(src, window.location.href);
+      const protocol = u.protocol.toLowerCase();
+      if (protocol === "http:" || protocol === "https:" || protocol === "mailto:" || protocol === "data:") {
+        // allow data: only for images is handled in sanitizeHtml for srcdoc; for src, allow only http(s)/data/mailto
+        return src;
+      }
+    } catch {
+      // if URL constructor fails, reject the src
+    }
+    return undefined;
+  })();
+
+  return (
+    <iframe
+      className={className}
+      src={safeSrc}
+      srcDoc={safeSrcDoc}
+      sandbox={safeSandbox}
+      title={title}
+      referrerPolicy="no-referrer"
+    />
+  );
+};
+
+export default Embed;
